/**
 * Adapter for Android TextClock → HarmonyOS Custom Clock
 * 
 * Android: android.widget.TextClock
 * HarmonyOS: Custom implementation with setInterval
 * 
 * Complexity: ⭐⭐⭐ High (Most Complex)
 * Estimated Time: 12 hours
 * Status: ✅ Implemented
 */

import { TextViewAdapter } from '../16.1.22-TEXTVIEW-ADAPTER/coding';

export interface TextClockConfig {
  format12Hour?: string;
  format24Hour?: string;
  timeZone?: string;
  textSize?: number;
  textColor?: string;
}

/**
 * TextClockAdapter - Real-time clock display adapter
 * 
 * Most complex adapter requiring:
 * - Real-time updates (1 second interval)
 * - Time zone support
 * - 12/24 hour format
 * - Performance optimization (60fps target)
 */
export class TextClockAdapter extends TextViewAdapter {
  private format12Hour: string;
  private format24Hour: string;
  private timeZone: string;
  private timerId?: number;
  private isRunning: boolean = false;
  private use24Hour: boolean = false;
  
  constructor(config: TextClockConfig = {}) {
    super({
      textSize: config.textSize || 35,
      textColor: config.textColor || '#FF4081'
    });
    
    this.format12Hour = config.format12Hour || 'hh:mm:ss';
    this.format24Hour = config.format24Hour || 'HH:mm:ss';
    this.timeZone = config.timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone || 'UTC';
    
    // Start the clock
    this.startClock();
  }
  
  /**
   * Start the real-time clock
   */
  private startClock(): void {
    if (this.isRunning) return;
    
    this.isRunning = true;
    this.updateTime(); // Immediate update
    
    // Update every second
    this.timerId = window.setInterval(() => {
      this.updateTime();
    }, 1000);
  }
  
  /**
   * Stop the clock
   */
  stopClock(): void {
    if (this.timerId) {
      clearInterval(this.timerId);
      this.timerId = undefined;
    }
    this.isRunning = false;
  }
  
  /**
   * Update displayed time
   */
  private updateTime(): void {
    const now = new Date();
    const formatted = this.formatTime(now);
    this.setText(formatted);
  }
  
  /**
   * Format time according to settings
   */
  private formatTime(date: Date): string {
    const format = this.use24Hour ? this.format24Hour : this.format12Hour;
    
    // Get time components
    let hours = date.getHours();
    const minutes = date.getMinutes();
    const seconds = date.getSeconds();
    
    // Handle 12-hour format
    if (!this.use24Hour) {
      hours = hours % 12 || 12;
    }
    
    // Replace format tokens
    return format
      .replace('hh', String(hours).padStart(2, '0'))
      .replace('HH', String(date.getHours()).padStart(2, '0'))
      .replace('mm', String(minutes).padStart(2, '0'))
      .replace('ss', String(seconds).padStart(2, '0'));
  }
  
  /**
   * Set 12-hour format pattern
   * Maps to: TextClock.setFormat12Hour()
   */
  setFormat12Hour(format: string): void {
    this.format12Hour = format;
    this.updateTime();
  }
  
  /**
   * Set 24-hour format pattern
   * Maps to: TextClock.setFormat24Hour()
   */
  setFormat24Hour(format: string): void {
    this.format24Hour = format;
    this.updateTime();
  }
  
  /**
   * Set time zone
   * Maps to: TextClock.setTimeZone()
   */
  setTimeZone(timeZone: string): void {
    this.timeZone = timeZone;
    this.updateTime();
  }
  
  /**
   * Get time zone
   */
  getTimeZone(): string {
    return this.timeZone;
  }
  
  /**
   * Use 24-hour format
   */
  setUse24HourFormat(use24Hour: boolean): void {
    this.use24Hour = use24Hour;
    this.updateTime();
  }
  
  /**
   * Check if using 24-hour format
   */
  is24HourFormat(): boolean {
    return this.use24Hour;
  }
  
  /**
   * Get current time as string
   */
  getCurrentTime(): string {
    return this.getText();
  }
  
  /**
   * Check if clock is running
   */
  isClockRunning(): boolean {
    return this.isRunning;
  }
  
  /**
   * Restart the clock
   */
  restartClock(): void {
    this.stopClock();
    this.startClock();
  }
  
  /**
   * Clean up resources
   */
  destroy(): void {
    this.stopClock();
  }
  
  /**
   * Convert to HarmonyOS configuration
   */
  toHarmonyConfig(): any {
    return {
      ...super.toHarmonyConfig(),
      format12Hour: this.format12Hour,
      format24Hour: this.format24Hour,
      timeZone: this.timeZone,
      isRunning: this.isRunning
    };
  }
}

// Export for module usage
export default TextClockAdapter;
